/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'email' channel.
 * Provides template rendering, recipient validation, and a pluggable
 * transport layer. Uses an in-memory transport by default for testing;
 * inject an EmailTransport for production (e.g., SendGrid, SES, SMTP).
 */

import { Logger } from '../utils/logger.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';

/** Represents a rendered email ready for delivery. */
export interface RenderedEmail {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
}

/** Record of a sent email, including delivery metadata. */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
  notificationType: NotificationType;
  messageId: string;
}

/**
 * Transport interface for pluggable email delivery.
 * Implement this to integrate with real email providers.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * In-memory transport that stores emails instead of sending them.
 * Used by default for testing and development.
 */
export class InMemoryTransport implements EmailTransport {
  private counter = 0;

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    this.counter++;
    return { messageId: `mem-${String(this.counter).padStart(6, '0')}` };
  }
}

/** Email template definition. */
interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  html: (payload: NotificationPayload) => string;
  text: (payload: NotificationPayload) => string;
}

/** Built-in templates keyed by notification type. */
const templates: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    subject: (p) => p.subject,
    html: (p) => {
      const orderId = p.metadata?.orderId ?? 'N/A';
      return `<h1>Order Confirmation</h1><p>Hi there,</p><p>Your order <strong>${escapeHtml(String(orderId))}</strong> has been placed.</p><p>${escapeHtml(p.body)}</p><p>Thank you for your purchase!</p>`;
    },
    text: (p) => {
      const orderId = p.metadata?.orderId ?? 'N/A';
      return `Order Confirmation\n\nYour order ${orderId} has been placed.\n${p.body}\n\nThank you for your purchase!`;
    },
  },
  'order-status-update': {
    subject: (p) => p.subject,
    html: (p) => {
      const prev = p.metadata?.previousStatus ?? '';
      const next = p.metadata?.newStatus ?? '';
      return `<h1>Order Status Update</h1><p>${escapeHtml(p.body)}</p><p>Status: <strong>${escapeHtml(String(prev))}</strong> → <strong>${escapeHtml(String(next))}</strong></p>`;
    },
    text: (p) => {
      const prev = p.metadata?.previousStatus ?? '';
      const next = p.metadata?.newStatus ?? '';
      return `Order Status Update\n\n${p.body}\nStatus: ${prev} → ${next}`;
    },
  },
  'user-welcome': {
    subject: (p) => p.subject,
    html: (p) => `<h1>Welcome to TaskFlow Pro!</h1><p>${escapeHtml(p.body)}</p><p>Get started by exploring your dashboard.</p>`,
    text: (p) => `Welcome to TaskFlow Pro!\n\n${p.body}\n\nGet started by exploring your dashboard.`,
  },
  'user-updated': {
    subject: (p) => p.subject,
    html: (p) => `<h1>Account Updated</h1><p>${escapeHtml(p.body)}</p>`,
    text: (p) => `Account Updated\n\n${p.body}`,
  },
  'system-alert': {
    subject: (p) => p.subject,
    html: (p) => `<h1>System Alert</h1><p style="color:red;"><strong>${escapeHtml(p.body)}</strong></p>`,
    text: (p) => `SYSTEM ALERT\n\n${p.body}`,
  },
};

/** Simple HTML entity escaping for template safety. */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/** Validate that a string looks like an email address. */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private transport: EmailTransport;

  constructor(transport?: EmailTransport) {
    this.transport = transport ?? new InMemoryTransport();
  }

  /**
   * Render a notification payload into a full email using the
   * template for the payload's notification type.
   */
  renderTemplate(payload: NotificationPayload): RenderedEmail {
    const template = templates[payload.notificationType];

    return {
      to: payload.recipient,
      subject: template.subject(payload),
      htmlBody: template.html(payload),
      textBody: template.text(payload),
    };
  }

  /**
   * Resolve and validate the recipient email address.
   * Returns the validated address or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const email = payload.recipient.trim().toLowerCase();

    if (!email) {
      this.logger.warn('Empty recipient address');
      return null;
    }

    if (!isValidEmail(email)) {
      this.logger.warn(`Invalid email address: ${email}`);
      return null;
    }

    return email;
  }

  /**
   * Send an email notification.
   * Validates the recipient, renders the template, and delivers via transport.
   * Never throws — returns { success: false } on failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedRecipient = this.resolveRecipient(payload);

      if (!resolvedRecipient) {
        return {
          success: false,
          channel: 'email',
          message: `Invalid recipient: ${payload.recipient}`,
        };
      }

      const rendered = this.renderTemplate({
        ...payload,
        recipient: resolvedRecipient,
      });

      this.logger.info(`Sending email to ${resolvedRecipient}: ${rendered.subject}`);

      const { messageId } = await this.transport.sendMail(rendered);

      const record: SentEmail = {
        to: resolvedRecipient,
        subject: rendered.subject,
        body: rendered.textBody,
        htmlBody: rendered.htmlBody,
        sentAt: new Date(),
        notificationType: payload.notificationType,
        messageId,
      };

      this.sentEmails.push(record);

      return {
        success: true,
        channel: 'email',
        message: `Email delivered to ${resolvedRecipient} (${messageId})`,
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return {
        success: false,
        channel: 'email',
        message,
      };
    }
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport, RenderedEmail } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    channel: 'email',
    notificationType: 'order-confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('resolveRecipient', () => {
    it('should accept a valid email address', () => {
      const payload = makePayload({ recipient: 'bob@example.com' });
      expect(adapter.resolveRecipient(payload)).toBe('bob@example.com');
    });

    it('should lowercase the email', () => {
      const payload = makePayload({ recipient: 'Alice@Example.COM' });
      expect(adapter.resolveRecipient(payload)).toBe('alice@example.com');
    });

    it('should trim whitespace', () => {
      const payload = makePayload({ recipient: '  alice@example.com  ' });
      expect(adapter.resolveRecipient(payload)).toBe('alice@example.com');
    });

    it('should return null for empty recipient', () => {
      const payload = makePayload({ recipient: '' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should return null for invalid email', () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should return null for email without domain', () => {
      const payload = makePayload({ recipient: 'alice@' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });
  });

  describe('renderTemplate', () => {
    it('should render order-confirmation template with HTML', () => {
      const payload = makePayload();
      const rendered = adapter.renderTemplate(payload);

      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.htmlBody).toContain('<h1>Order Confirmation</h1>');
      expect(rendered.htmlBody).toContain('order-1');
      expect(rendered.textBody).toContain('Order Confirmation');
      expect(rendered.textBody).toContain('order-1');
    });

    it('should render order-status-update template', () => {
      const payload = makePayload({
        notificationType: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
      });

      const rendered = adapter.renderTemplate(payload);
      expect(rendered.htmlBody).toContain('Order Status Update');
      expect(rendered.htmlBody).toContain('pending');
      expect(rendered.htmlBody).toContain('confirmed');
      expect(rendered.textBody).toContain('pending');
      expect(rendered.textBody).toContain('confirmed');
    });

    it('should render user-welcome template', () => {
      const payload = makePayload({
        notificationType: 'user-welcome',
        subject: 'Welcome to TaskFlow Pro',
        body: 'Welcome, Alice! Your account has been created.',
      });

      const rendered = adapter.renderTemplate(payload);
      expect(rendered.htmlBody).toContain('Welcome to TaskFlow Pro');
      expect(rendered.htmlBody).toContain('dashboard');
      expect(rendered.textBody).toContain('Welcome to TaskFlow Pro');
    });

    it('should render user-updated template', () => {
      const payload = makePayload({
        notificationType: 'user-updated',
        subject: 'Account Updated',
        body: 'Your profile has been updated.',
      });

      const rendered = adapter.renderTemplate(payload);
      expect(rendered.htmlBody).toContain('Account Updated');
    });

    it('should render system-alert template', () => {
      const payload = makePayload({
        notificationType: 'system-alert',
        subject: 'System Alert',
        body: 'High CPU usage detected',
      });

      const rendered = adapter.renderTemplate(payload);
      expect(rendered.htmlBody).toContain('System Alert');
      expect(rendered.htmlBody).toContain('color:red');
      expect(rendered.textBody).toContain('SYSTEM ALERT');
    });

    it('should escape HTML entities in body', () => {
      const payload = makePayload({
        body: 'Items: <script>alert("xss")</script>',
      });

      const rendered = adapter.renderTemplate(payload);
      expect(rendered.htmlBody).not.toContain('<script>');
      expect(rendered.htmlBody).toContain('&lt;script&gt;');
    });
  });

  describe('send', () => {
    it('should successfully send a valid email', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.message).toContain('alice@example.com');
    });

    it('should store sent email with rendered content', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.htmlBody).toContain('<h1>');
      expect(sent[0]?.notificationType).toBe('order-confirmation');
      expect(sent[0]?.messageId).toMatch(/^mem-/);
    });

    it('should return failure for invalid recipient', async () => {
      const payload = makePayload({ recipient: 'not-valid' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.message).toContain('Invalid recipient');
    });

    it('should not store email on recipient validation failure', async () => {
      const payload = makePayload({ recipient: 'bad' });
      await adapter.send(payload);

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ messageId: string }> {
          throw new Error('SMTP connection refused');
        },
      };

      const failAdapter = new EmailAdapter(failingTransport);
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.message).toBe('SMTP connection refused');
    });

    it('should not store email when transport throws', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ messageId: string }> {
          throw new Error('fail');
        },
      };

      const failAdapter = new EmailAdapter(failingTransport);
      await failAdapter.send(makePayload());

      expect(failAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should handle non-Error thrown by transport', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ messageId: string }> {
          throw 'string error';
        },
      };

      const failAdapter = new EmailAdapter(failingTransport);
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.message).toBe('Unknown transport error');
    });

    it('should assign unique message IDs to each sent email', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.messageId).not.toBe(sent[1]?.messageId);
    });
  });

  describe('custom transport', () => {
    it('should use injected transport', async () => {
      const calls: RenderedEmail[] = [];
      const customTransport: EmailTransport = {
        async sendMail(email: RenderedEmail) {
          calls.push(email);
          return { messageId: 'custom-001' };
        },
      };

      const customAdapter = new EmailAdapter(customTransport);
      await customAdapter.send(makePayload());

      expect(calls).toHaveLength(1);
      expect(calls[0]?.to).toBe('alice@example.com');

      const sent = customAdapter.getSentEmails();
      expect(sent[0]?.messageId).toBe('custom-001');
    });
  });

  describe('getSentEmails and clearSentEmails', () => {
    it('should return a copy of sent emails', async () => {
      await adapter.send(makePayload());
      const emails1 = adapter.getSentEmails();
      const emails2 = adapter.getSentEmails();
      expect(emails1).toEqual(emails2);
      expect(emails1).not.toBe(emails2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

describe('InMemoryTransport', () => {
  it('should return sequential message IDs', async () => {
    const transport = new InMemoryTransport();
    const r1 = await transport.sendMail({ to: 'a@b.com', subject: 'S', htmlBody: '', textBody: '' });
    const r2 = await transport.sendMail({ to: 'a@b.com', subject: 'S', htmlBody: '', textBody: '' });

    expect(r1.messageId).toBe('mem-000001');
    expect(r2.messageId).toBe('mem-000002');
  });
});

